import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']),
  PORT: z.string().regex(/^\d+$/).transform(Number),
  MONGO_URI: z.string(),
  JWT_SECRET: z.string().min(32),
  TELEGRAM_TOKEN: z.string(),
});

const env = envSchema.parse(process.env);

export default env;

import { z } from 'zod';

export const createTaskSchema = z.object({
  groupId: z.string().regex(/^[a-fA-F0-9]{24}$/),
  title: z.string().min(3).max(100),
  recurrence: z.object({
    type: z.enum(['daily', 'weekly', 'custom']),
    daysOfWeek: z.optional(z.array(z.number().min(1).max(7))),
    time: z.string().regex(/^\d{2}:\d{2}$/),
  }),
  assignees: z.array(z.string().regex(/^[a-fA-F0-9]{24}$/)),
});

interface TaskDTO {
  id: string;
  groupId: string;
  title: string;
  description?: string;
  assignees: string[];
  recurrence: {
    type: string;
    daysOfWeek?: number[];
    time: string;
  };
  status: string;
}

export const taskDTOMapper = (task: any): TaskDTO => ({
  id: task._id.toString(),
  groupId: task.groupId.toString(),
  title: task.title,
  description: task.description,
  assignees: task.assignees.map((id: any) => id.toString()),
  recurrence: task.recurrence,
  status: task.status,
});

import mongoose from 'mongoose';
import { Task } from './models/task';

const createTask = async (taskData: any) => {
  const task = new Task(taskData);
  return await task.save();
};

const findTaskById = async (id: string) => {
  return await Task.findById(id);
};

export const taskRepository = {
  createTask,
  findTaskById,
};

import { Telegraf } from 'telegraf';
import env from '../config/env';
import { taskRepository } from '../repositories/task-repository';
import { taskDTOMapper } from '../dtos/task-dto';

const bot = new Telegraf(env.TELEGRAM_TOKEN);

const sendNotification = async (taskId: string) => {
  const task = await taskRepository.findTaskById(taskId);
  if (!task) {
    throw new Error('Task not found');
  }

  const taskDTO = taskDTOMapper(task);
  const message = `Task: ${taskDTO.title}\nScheduled at: ${taskDTO.recurrence.time}`;
  // Using dummy chatId here. Adapt this as needed.
  const chatId = '<TELEGRAM_CHAT_ID>';

  try {
    await bot.telegram.sendMessage(chatId, message);
    console.log('Notification sent successfully');
  } catch (error) {
    console.error('Failed to send notification:', error);
  }
};

export const notificationService = {
  sendNotification,
};

import helmet from 'helmet';
import cors from 'cors';
import rateLimit from 'express-rate-limit';
import express, { Request, Response, NextFunction } from 'express';

const app = express();

// Apply middlewares
app.use(helmet());
app.use(cors({
  origin: 'http://yourfrontend.com', // Restrict this to your frontend domain
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Error handling middleware
app.use((err: Error, req: Request, res: Response, next: NextFunction) => {
  console.error(err.stack);
  res.status(500).send('Something broke!');
});

export { app };
